INSERT INTO `video` (`id`, `audio_file_path`, `file_name`, `file_path`, `transcription`, `user_id`, `url`, `video_data`, `thumbnailurl`, `created_at`, `job_id`, `college`, `role_code`, `embedding_vector`) VALUES
(84, 'https://wezume.in/uploads/videos/audio/1740280546002_5smbjcvd3cc.mp3', 'compressed_1740280546002_5smbjcvd3cc.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1740280546002_5smbjcvd3cc.mp4', 'I thought event management was so easy until I was put in charge of organizing a cultural event competition during my undergraduation years. It seemed so simple, just plan, execute and enjoy. But as I kept receiving calls and queries regarding the same, I understood how important my responsibility were and how every little detail had to be handled efficiently. Now fast forward to my post graduation years which I\'m pursuing right now. I had the opportunity to lead one of our department\'s flagship event, but this time the stakes and challenges were rather high. From finalizing the venues, arranging the judges, handling unexpected problems. But the stake did not stop there. So did my growth. These experiences shaped me into a strong leader, good communicator, and a firm believer of teamwork. If you are looking for someone who would thrive to work in a dynamic environment, you are looking at the right person on your screen. Thank you.', 40, 'https://wezume.in/uploads/videos/compressed_1740280546002_5smbjcvd3cc.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1740280546002_5smbjcvd3cc.jpg', NULL, NULL, NULL, NULL, '[0.008640462532639503,2.5726636522449553E-4,-0.014370795339345932,0.03281474485993385,0.07958278059959412,0.02632320672273636,-4.4752159737981856E-4,0.041883014142513275,0.005558638833463192,-0.0066809337586164474,-0.015066846273839474,0.02613484486937523,-0.028615783900022507,0.027241408824920654,-0.012727080844342709,0.05709047615528107,0.04880860820412636,0.002899353625252843,0.012418404221534729,-0.018567198887467384,0.015360157005488873,0.07615305483341217,0.04262250289320946,0.06876354664564133,0.05000370368361473,0.007307154126465321,0.010996375232934952,-0.006454255431890488,-0.03395552933216095,0.01277546305209398