(383, 'https://wezume.in/uploads/videos/audio/1757517529056.mp3', 'compressed_1757517529056.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1757517529056.mp4', 'Hi, I\'m Timothy Graham Samson. I\'m currently pursuing my PGDM at MCC Boyd Tannen School of Business, specializing in human resources. I started my journey in electrical and electronics engineering, which gave me a strong analytical foundation, and over the years I have grown into leadership roles such as the President of the Student Council and founder of the fitness club. I\'ve gained my practical exposure through internships with Nippon Paint and Madras Engineering Industries, where I worked on performance management, employee engagement, and market research. These experiences helped me sharpen my problem solving, communication, and people management skills. Outside academics, I have represented my college in football and actively contributed to CSR initiatives which strengthened my teamwork and community values. My goal is to build a career in human resource where I can create impact by driving collaboration, engagement, and organizational growth.', 268, 'https://wezume.in/uploads/videos/compressed_1757517529056.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1757517529056.jpg', '2025-09-10 20:50:21.331451', 'C191', 'null', 'null', '[0.017841991037130356,0.009249730035662651,-0.01434229500591755,0.0567806251347065,0.10150451958179474,0.04683835059404373,0.004966024309396744,0.03772890195250511,-0.00520594185218215,3.0437801615335047E-4,-0.03326859697699547,0.02265874482691288,-0.023624857887625694,0.017065687105059624,-0.0018656387692317367,0.0524243526160717,0.058751583099365234,0.010853396728634834,0.01200637873262167,-0.006207560654729605,0.01983514614403248,0.06992769986391068,0.06412418186664581,0.0360742062330246,0.06150997430086136,0.029313495382666588,0.03909320384263992,0.012505467981100082,-0.024877112358808517,0.028804359957575798,0.026878787204623