(394, 'https://wezume.in/uploads/videos/audio/1759823354957.mp3', 'compressed_1759823354957.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1759823354957.mp4', 'Hi, I am Deval Prasad, a PGDM student specializing in supply chain management and Finance at MCC Boyd Diamond School of Business. I am passionate about building efficient data driven supply chain that deliver measurable impact. During my internship at Linker Electric, I implemented a barcode scanning system that streamlined material flow, improved data accuracy and reduce disaster, showing me first hand how technology can enhance supply chain visibility and efficiency. At Airport Authority of India, I analyze cost and process data to boost financial efficiency. I am proficient in power bi tableau and excel beyond academics. I coordinate my collaboration, communication and stakeholder management skills in my college Management festival, all of which I know used to derive measurable results.', 206, 'https://wezume.in/uploads/videos/compressed_1759823354957.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1759823354957.jpg', '2025-10-07 13:21:16.101639', 'C191', 'null', 'null', '[0.02233782410621643,0.004189508501440287,-0.02388157695531845,0.07672745734453201,0.10463888198137283,0.06338170170783997,-0.015757502987980843,0.046935901045799255,0.007198598235845566,-0.001998359803110361,-0.01951422169804573,-8.81372659932822E-4,-0.04260890930891037,0.03595186769962311,-0.0015352149493992329,0.0684291422367096,0.06874027103185654,0.004324405919760466,0.0222738366574049,-4.206062585581094E-4,0.010637859813869,0.058188315480947495,0.03459886834025383,0.05089431256055832,0.036125145852565765,0.027437197044491768,0.019689291715621948,0.017302222549915314,-0.03475313261151314,-0.0017207906348630786,0.02955765463411808,-0.02910313382744789,0.019993770867586136,0.012787160463631153,0.02135493978857994,-0.0025558858178555965,0.014121219515800476,0.02691713720560074,-0.00264410814