INSERT INTO `video` (`id`, `audio_file_path`, `file_name`, `file_path`, `transcription`, `user_id`, `url`, `video_data`, `thumbnailurl`, `created_at`, `job_id`, `college`, `role_code`, `embedding_vector`) VALUES
(415, 'https://wezume.in/uploads/videos/audio/1760363263488.mp3', 'compressed_1760363263488.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1760363263488.mp4', 'What fascinates me most about supply chains is that they are invisible, yet they keep the world moving. Hello, I\'m Eminel Ashweta, currently pursuing my PGDM at MCC Boy Tannen School of Business and I specialize in exploring how supply chains can be made smarter and more sustainable. Through my project at Global Logistics Solutions India Private Limited, I worked on optimizing inland container depots. I learned how efficient design and sustainable planning can cut costs and delays. As part of my summer internship at BlueDART Aviation Ltd. I worked with real time inbound logistics data, tracking shipments, analyzing trends and suggesting time prediction improvements using Power BI Tableau and Google Collab. It taught me how visualization simplifies even the most complex networks. As part of my societal Impact Mission Club, I learned how logistics decision impact both business and communities. I\'m eager to bring this mindset into my professional journey and grow as part of a forward looking team. Thank you.', 235, 'https://wezume.in/uploads/videos/compressed_1760363263488.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1760363263488.jpg', '2025-10-13 19:18:34.613370', 'C191', 'null', 'null', '[0.03038136474788189,-0.0057630776427686214,-0.011114774271845818,0.062385234981775284,0.10245612263679504,0.0632764920592308,-0.015495356172323227,0.05054932087659836,0.014922198839485645,-0.012714475393295288,-0.023104988038539886,-0.00709852110594511,-0.04841897636651993,0.03104494698345661,-0.026536650955677032,0.05968061462044716,0.07276841998100281,0.019808094948530197,0.007437562569975853,0.00313370069488883,0.007021565921604633,0.05776366963982582,0.032814595848321915,0.04110918194055557,0.043921612203121185,0.015155747532844543,0.010568322613835335,0.0122825065627694