INSERT INTO `video` (`id`, `audio_file_path`, `file_name`, `file_path`, `transcription`, `user_id`, `url`, `video_data`, `thumbnailurl`, `created_at`, `job_id`, `college`, `role_code`, `embedding_vector`) VALUES
(427, 'https://wezume.in/uploads/videos/audio/1762163746502.mp3', 'compressed_1762163746502.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1762163746502.mp4', 'Hi, I am Jay Shree. I am currently pursuing my PGDM at MCC Boyd Talent School of Business with a specialization in supply chain management and marketing. I have always been curious about how things move, how products travel from one place to another, and how small planning decision can make such a big difference. That curiosity is what drew me towards logistics. During my internship with Blue Dart Aviation, I created a real time Excel dashboard that helped to track flights and plan for delays more efficiently. Then at Global Logistics Solutions, I worked on a project analyzing inland container depots and suggested new route to improve cargo flow and sustainability. Outside economics, I\'m actively involved in the Societal Impact Mission Club where I work with a passionate team to plan events and lead initiatives that create real community impact. I love connecting data with people and finding ways to make systems smarter and more purposeful. Thank you.', 232, 'https://wezume.in/uploads/videos/compressed_1762163746502.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1762163746502.jpg', '2025-11-03 15:26:24.400839', 'C191', 'null', 'null', '[0.016039473935961723,0.011403216980397701,-0.012585384771227837,0.054377295076847076,0.10442381352186203,0.051599353551864624,-0.00953065138310194,0.04724995419383049,9.121358743868768E-4,-0.021657653152942657,-0.007156211882829666,-0.007179927080869675,-0.038839489221572876,0.01743275485932827,-0.008729575201869011,0.06541820615530014,0.0639096051454544,0.01567939482629299,0.00896867923438549,0.009369665756821632,0.01019339170306921,0.0701330229640007,0.026394199579954147,0.04452993720769882,0.0469604916870594,0.008956428617238998,0.008980860002338886,0.004317679442465305,-0.04166151210665703,0.017538325861096382,0.0311927888542