(495, 'https://wezume.in/uploads/videos/audio/1763356533880.mp3', 'compressed_1763356533880.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1763356533880.mp4', 'Hello sir, My name is Mohit Kumar and I would like to be identified as someone who learns fast and solves problem by diving deep into the details. So one moment that saved this was during my internship at Ernst and Young where I was asked to analyze the India Nepal trade data. So instead of just compiling numbers, I build a structured five year comp comparison and identified specific commodities and infrastructure gaps. So something that helped the team strengthen their recommendations. So this experience taught me how data can change conversation and more importantly, how to communicate what they actually means. Thank you.', 378, 'https://wezume.in/uploads/videos/compressed_1763356533880.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1763356533880.jpg', '2025-11-17 10:50:12.778452', 'J007', 'null', 'null', '[0.021017668768763542,0.0010979791404679418,-0.007884077727794647,0.06712504476308823,0.09855905175209045,0.06302832067012787,-2.643659245222807E-4,0.019836191087961197,0.014753269031643867,-0.014252462424337864,-0.016333691775798798,0.02284146100282669,-0.0453910231590271,0.023950327187776566,-0.00298942974768579,0.05099979043006897,0.07130027562379837,0.020400768145918846,0.023232433944940567,0.009751319885253906,0.009844210930168629,0.0648597925901413,0.048625506460666656,0.03647806867957115,0.03721417114138603,0.006348185706883669,0.013019649311900139,0.006911317817866802,-0.03494662418961525,0.02895234152674675,0.02581166848540306,-0.0011775827733799815,-0.0022596092894673347,0.01298192422837019,0.008831433951854706,-0.01017762627452612,0.003608940402045846,0.037299223244190216,0.004866884555667639,0.013198149390518665,-0.0647304430603981,0.022266479209065437,-0.01287980005145073,0.004108354449272156,-0.04274638742208481,0.008029121905565262,-0.046166289