(512, 'https://wezume.in/uploads/videos/audio/1763369741268.mp3', 'compressed_1763369741268.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1763369741268.mp4', 'Hi, I\'m Chaitanya. I\'m someone who enjoys turning insights into clear, actionable ideas. During my internship at India Cable Systech, I engaged with over 120 clients, managed follow ups and closed sales worth of 20,000 rupees. This taught me consistency and how to communicate value simply. I have also worked on multiple presentation driven projects at IFMR and this is where I learned how to break down complex information and deliver it in a way that\'s easy to understand. These experiences strengthened my communication, coordination and problem solving skills. I\'m now looking for a role where I can bring that same clarity, curiosity and client focused approach to the team. Thank you.', 381, 'https://wezume.in/uploads/videos/compressed_1763369741268.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1763369741268.jpg', '2025-11-17 14:27:40.982392', 'J007', 'null', 'null', '[0.024265920743346214,-0.008172603324055672,0.004905220586806536,0.04725997895002365,0.0978969857096672,0.06133182719349861,5.08881697896868E-4,0.02680446393787861,0.0185514148324728,0.002535647712647915,-0.022129211574792862,0.02886837348341942,-0.03141847625374794,0.020845340564846992,-0.012318208813667297,0.058302536606788635,0.06009075045585632,0.014865650795400143,0.01754019409418106,-0.004443542566150427,0.017930416390299797,0.06507602334022522,0.05694039538502693,0.03247953951358795,0.03902735933661461,0.020287463441491127,0.016281913965940475,0.008565681055188179,-0.03149660676717758,0.007574689574539661,0.03655156493186951,-0.03733691945672035,0.006676181685179472,0.008966685272753239,0.020316878333687782,-0.014453680254518986,0.00836439710110426,0.032687071710824966,0.008468667045235634,-0.023136744275689125,-0.07695528119802475,0.02168327197432518,-0.014072311110794544,-5.9048971161246