INSERT INTO `video` (`id`, `audio_file_path`, `file_name`, `file_path`, `transcription`, `user_id`, `url`, `video_data`, `thumbnailurl`, `created_at`, `job_id`, `college`, `role_code`, `embedding_vector`) VALUES
(520, 'https://wezume.in/uploads/videos/audio/1764692606967.mp3', 'compressed_1764692606967.mp4', '/home/wezume/htdocs/wezume.in/uploads/videos/compressed_1764692606967.mp4', 'Hi, I\'m Nikita and I come from a journalism and mass communication background, so creativity and understanding people is a core part of who I am. While I was working as a digital marketer, I was constantly analyzing consumer behavior, segmenting audiences, planning campaigns and coordinating with the client to understand what they really needed. When I was doing that, I realized that I was not just enjoying my job, I was actually falling in love with marketing. That\'s when I decided that I didn\'t want to limit myself to just digital and I decided to pursue an MBA in marketing. But through that experience, what I realized was that great brands are not built on assumptions, they\'re built on empathy. And now that I\'m studying subjects like pricing, I am realizing that even small tactical pricing decisions can have a huge impact on consumer buying patterns. Cavencare excites me because it has innovation at its heart and it\'s a consumer first brand. That is how I see brands as well. Thank you.', 320, 'https://wezume.in/uploads/videos/compressed_1764692606967.mp4', NULL, 'https://wezume.in/uploads/videos/thumbnails/thumbnail_compressed_1764692606967.jpg', '2025-12-02 21:54:05.109980', 'J008', '', 'null', '[0.030239421874284744,0.004619264043867588,-0.019341519102454185,0.04638804867863655,0.09561016410589218,0.05520538613200188,0.013375693000853062,0.04961467534303665,0.038938555866479874,0.010776967741549015,-0.034149445593357086,0.03034956566989422,-0.018335431814193726,0.019545646384358406,-0.008714668452739716,0.05918357893824577,0.06167767196893692,0.02765498124063015,0.028551384806632996,0.009287738241255283,0.004771620035171509,0.05550765618681908,0.03798710182309151,0.050308652222156525,0.05248104780912399,0.008299403823912144,0.04520745947957039,0.011942814104259014,-0.037651415914297